import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dashboard.md","filePath":"guide/dashboard.md","lastUpdated":1772965483000}'),s={name:"guide/dashboard.md"};function i(n,e,l,d,h,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The dashboard is your home base in getbased. It displays everything in a single scrollable page — no tabs to juggle, no hidden sections. The layout flows from top to bottom in a fixed order.</p><h2 id="dashboard-layout" tabindex="-1">Dashboard Layout <a class="header-anchor" href="#dashboard-layout" aria-label="Permalink to &quot;Dashboard Layout&quot;">​</a></h2><p>Sections appear in this order:</p><ol><li><strong>Import Button</strong> — A floating action button (bottom-right, above the chat FAB) for importing PDFs or JSON files. Appears once you have data; on first visit, the welcome hero handles imports</li><li><strong>Interpretive Lens</strong> — The scientific or clinical framework the AI uses when analyzing your results</li><li><strong>Focus Card</strong> — A single AI-generated sentence summarizing the most important finding right now</li><li><strong>Context Cards</strong> — Nine lifestyle cards covering what your GP typically doesn&#39;t ask</li><li><strong>Menstrual Cycle</strong> — Cycle tracking and phase-aware interpretation (female profiles only)</li><li><strong>Supplements</strong> — Your supplement and medication timeline</li><li><strong>Key Trends</strong> — Line charts for each biomarker category</li><li><strong>Trends &amp; Alerts</strong> — Automatically detected changes and critical flags</li><li><strong>Data &amp; Notes</strong> — Your raw entries, standalone notes, and export options</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The dashboard only shows markers that have actual data from your lab results. Markers in the schema that you have never imported are hidden from the sidebar count and charts.</p></div><h2 id="sidebar-navigation" tabindex="-1">Sidebar Navigation <a class="header-anchor" href="#sidebar-navigation" aria-label="Permalink to &quot;Sidebar Navigation&quot;">​</a></h2><p>The sidebar on the left lists all biomarker categories (Biochemistry, Hormones, Lipids, Hematology, etc.). Each category shows a count of how many markers have actual data. Click any category to jump to its charts.</p><p>On tablets and smaller screens (below 1024px), the sidebar becomes a slide-out menu accessed via the hamburger button in the header. Tap a category to navigate and the sidebar closes automatically.</p><h2 id="date-range-filter" tabindex="-1">Date Range Filter <a class="header-anchor" href="#date-range-filter" aria-label="Permalink to &quot;Date Range Filter&quot;">​</a></h2><p>Use the date range control in the header to zoom into a specific period. All charts, trend alerts, and the correlation view respond to whatever range you set. Narrowing the range is useful when you want to examine a specific health event or treatment period.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Trend alerts and flagged markers also respect the date range filter — tightening the range can help you isolate patterns from a particular time window.</p></div><h2 id="context-cards" tabindex="-1">Context Cards <a class="header-anchor" href="#context-cards" aria-label="Permalink to &quot;Context Cards&quot;">​</a></h2><p>The nine context cards sit in a grid under the heading &quot;What your GP won&#39;t ask you.&quot; They cover:</p><ul><li>Health Goals</li><li>Medical Conditions</li><li>Diet</li><li>Exercise</li><li>Sleep &amp; Rest</li><li>Light &amp; Circadian</li><li>Stress</li><li>Love Life &amp; Relationships</li><li>Environment</li></ul><p>Each card shows a summary of what you&#39;ve entered, a colored health-status dot (AI-rated green / yellow / red), and a brief AI-generated tip. Click any card to open its editor. The header shows how many cards you have filled, for example &quot;5/9 filled.&quot;</p><p>An <strong>Additional Notes</strong> text area below the cards lets you add free-form context that the AI will consider in every response. It saves automatically as you type.</p><h2 id="focus-card" tabindex="-1">Focus Card <a class="header-anchor" href="#focus-card" aria-label="Permalink to &quot;Focus Card&quot;">​</a></h2><p>When an AI provider is configured, the Focus Card appears just above the context cards. It shows a single sentence — the most actionable observation the AI can make based on your current lab data and lifestyle context. The card is cached and only regenerates when your data or context changes.</p><h2 id="trends-alerts" tabindex="-1">Trends &amp; Alerts <a class="header-anchor" href="#trends-alerts" aria-label="Permalink to &quot;Trends &amp; Alerts&quot;">​</a></h2><p>This section appears below the charts. Trend alerts come first (rising or falling patterns), followed by critical flags for markers that have gone significantly out of range. See <a href="./trend-alerts.html">Trend Alerts</a> for a full explanation of how these are detected.</p>',21)])])}const g=a(s,[["render",i]]);export{u as __pageData,g as default};
